// Extrai o link do boleto BrCondo do email
// Suporta todas as estruturas de dados do Gmail Trigger (simple e full)
const results = [];

function decodeBase64Url(data) {
  const base64 = data.replace(/-/g, '+').replace(/_/g, '/');
  return Buffer.from(base64, 'base64').toString('utf-8');
}

function extractBodyTexts(emailData) {
  const texts = [];

  // 1. Campos diretos (simple: true)
  if (emailData.textPlain) texts.push(emailData.textPlain);
  if (emailData.textHtml) texts.push(emailData.textHtml);

  // 2. Snippet (sempre presente)
  if (emailData.snippet) texts.push(emailData.snippet);

  // 3. payload.body.data (email sem multipart)
  if (emailData.payload && emailData.payload.body && emailData.payload.body.data) {
    texts.push(decodeBase64Url(emailData.payload.body.data));
  }

  // 4. payload.parts (multipart)
  if (emailData.payload && emailData.payload.parts) {
    for (const part of emailData.payload.parts) {
      if (part.body && part.body.data) {
        texts.push(decodeBase64Url(part.body.data));
      }
      // Sub-parts (multipart aninhado)
      if (part.parts) {
        for (const subPart of part.parts) {
          if (subPart.body && subPart.body.data) {
            texts.push(decodeBase64Url(subPart.body.data));
          }
        }
      }
    }
  }

  // 5. Busca no JSON inteiro como fallback
  if (texts.length === 0) {
    texts.push(JSON.stringify(emailData));
  }

  return texts;
}

for (const item of $input.all()) {
  const emailData = item.json;
  const subject = emailData.subject || emailData.payload?.headers?.find(h => h.name === 'Subject')?.value || '';
  const allTexts = extractBodyTexts(emailData);
  const combined = allTexts.join(' ');

  // Extrai o link do Bill
  const billRegex = /https:\/\/ssl\.brcondos\.com\.br\/Bill\/([a-f0-9\-]{36})/i;
  const match = combined.match(billRegex);

  if (match) {
    results.push({
      json: {
        subject: subject,
        billUuid: match[1],
        billUrl: `https://ssl.brcondos.com.br/Bill/${match[1]}`,
        messageId: emailData.id || emailData.messageId || ''
      }
    });
  }
}

if (results.length === 0) {
  throw new Error('Nenhum link de boleto encontrado nos emails. Verifique se o email contém o link ssl.brcondos.com.br/Bill/...');
}

return results;

// Extrai o link direto do PDF da página do boleto
const html = $input.first().json.data;
const billUuid = $('Extrair Link do Boleto').first().json.billUuid;
const subject = $('Extrair Link do Boleto').first().json.subject;

// Procura o link do PDF na página
// Formato: https://ssl.brcondos.com.br/BillPDF/{uuid}/{nome-do-arquivo}
const pdfRegex = /https:\/\/ssl\.brcondos\.com\.br\/BillPDF\/[^"'\s]+/i;
const match = html.match(pdfRegex);

let pdfUrl;

if (match) {
  // Limpa possíveis caracteres HTML no final
  pdfUrl = match[0].replace(/["'<>]/g, '');
} else {
  // Fallback: constrói a URL do PDF a partir do UUID
  pdfUrl = `https://ssl.brcondos.com.br/BillPDF/${billUuid}/Boleto`;
}

return [{
  json: {
    pdfUrl: pdfUrl,
    billUuid: billUuid,
    subject: subject
  }
}];
